function normalizeStateAbbreviation(value?: string) {
  const state = value?.trim();
  if (!state) return "PA";
  const upper = state.toUpperCase();
  const exact = usStateOptions.find(([code]) => code === upper);
  if (exact) return exact[0];
  const named = usStateOptions.find(([, name]) => normalizeMatchValue(name) === normalizeMatchValue(state));
  return named?.[0] || upper.slice(0, 2);
}

function stateAbbreviationFromValue(value?: string) {
  const state = value?.trim();
  if (!state) return "";
  const upper = state.toUpperCase();
  const exact = usStateOptions.find(([code]) => code === upper);
  if (exact) return exact[0];
  const named = usStateOptions.find(([, name]) => normalizeMatchValue(name) === normalizeMatchValue(state));
  return named?.[0] || "";
}

function streetAddressFromValue(value?: string) {
  const address = value?.trim() || "";
  return stateAbbreviationFromValue(address) ? "" : address;
}
