function escapePreviewHtml(value: string) {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function contractPreviewHtml(value: string) {
  if (!value) return "";
  if (/<[a-z][\s\S]*>/i.test(value)) return value;
  return escapePreviewHtml(value).replace(/\n/g, "<br>");
}

function emailHtmlForLiveEditor(value: string) {
  if (typeof document === "undefined") return value;
  const wrapper = document.createElement("div");
  wrapper.innerHTML = value;
  wrapper.querySelectorAll("p").forEach((paragraph) => {
    const block = document.createElement("div");
    block.innerHTML = paragraph.innerHTML || "<br>";
    paragraph.replaceWith(block);
  });
  wrapper.querySelectorAll("a[href]").forEach((link) => {
    const href = link.getAttribute("href") || "";
    const replacement = document.createElement("span");
    replacement.className = "email-editor-link";
    replacement.setAttribute("data-email-href", href);
    replacement.textContent = link.textContent || href;
    link.replaceWith(replacement);
  });
  return wrapper.innerHTML;
}

function emailHtmlFromLiveEditor(value: string) {
  if (typeof document === "undefined") return value;
  const wrapper = document.createElement("div");
  wrapper.innerHTML = value;
  wrapper.querySelectorAll(".email-editor-link[data-email-href]").forEach((link) => {
    const href = link.getAttribute("data-email-href") || "";
    const replacement = document.createElement("a");
    replacement.href = href;
    replacement.target = "_blank";
    replacement.rel = "noopener noreferrer";
    replacement.textContent = link.textContent || href;
    link.replaceWith(replacement);
  });
  wrapper.querySelectorAll("div").forEach((block) => {
    const paragraph = document.createElement("p");
    paragraph.innerHTML = block.innerHTML || "<br>";
    block.replaceWith(paragraph);
  });
  return wrapper.innerHTML;
}

function formatEmailCode(value: string) {
  return value
    .replace(/<p>\s*<br\s*\/?>\s*<\/p>/gi, "<br>")
    .replace(/>\s*</g, ">\n<")
    .replace(/(<\/p>|<br\s*\/?>)/gi, "$1\n")
    .replace(/\n{2,}/g, "\n")
    .trim();
}

function emailTextToHtml(value: string) {
  const blocks: string[] = [];
  let listItems: string[] = [];
  const flushList = () => {
    if (!listItems.length) return;
    blocks.push(`<ul>${listItems.map((item) => `<li>${item}</li>`).join("")}</ul>`);
    listItems = [];
  };
  value.split("\n").forEach((line) => {
    const trimmed = line.trim();
    if (trimmed.startsWith("- ")) {
      listItems.push(escapePreviewHtml(trimmed.slice(2)));
      return;
    }
    flushList();
    blocks.push(trimmed ? `<p>${escapePreviewHtml(trimmed)}</p>` : "<br>");
  });
  flushList();
  return blocks.join("");
}

function emailLinkHtml(href: string, label: string) {
  return `<a href="${escapePreviewHtml(href)}" target="_blank" rel="noopener noreferrer">${escapePreviewHtml(label)}</a>`;
}

function customerInvoiceUrl(job: Pick<Job, "clientEmail" | "orderNumber">) {
  if (typeof window === "undefined") return "";
  const url = new URL(window.location.href);
  url.searchParams.set("portal", "account");
  if (job.clientEmail) url.searchParams.set("email", job.clientEmail);
  if (job.orderNumber) url.searchParams.set("order", job.orderNumber);
  url.hash = "";
  return url.toString();
}

function customerContractUrl(job: Pick<Job, "clientEmail" | "orderNumber">, contract: Pick<ClientContract, "id">) {
  const url = customerInvoiceUrl(job);
  if (!url || typeof window === "undefined") return "";
  const next = new URL(url);
  next.searchParams.set("contract", contract.id);
  return next.toString();
}

function customerQuestionnaireUrl(job: Pick<Job, "id" | "clientEmail" | "orderNumber">, formId = "form-wedding-questionnaire") {
  const url = customerInvoiceUrl(job);
  if (!url || typeof window === "undefined") return "";
  const next = new URL(url);
  next.searchParams.set("portal", "form");
  next.searchParams.set("form", formId);
  next.searchParams.set("job", job.id);
  next.searchParams.set("workflow", "questionnaire");
  return next.toString();
}

function contractDueTiming(dueDate?: string, today = dateKey(new Date())) {
  if (!dueDate || !validDateKey(dueDate)) return "";
  const days = daysBetweenDateKeys(today, dueDate);
  if (days < 0) return Math.abs(days) === 1 ? "Past due by 1 day" : `Past due by ${Math.abs(days)} days`;
  if (days === 0) return "Due today";
  return days === 1 ? "Due tomorrow" : `Due in ${days} days`;
}

function hexToRgb(value?: string) {
  const hex = (value || "").trim().replace(/^#/, "");
  if (!/^[\da-f]{3}([\da-f]{3})?$/i.test(hex)) return null;
  const normalized = hex.length === 3 ? hex.split("").map((char) => char + char).join("") : hex;
  return {
    r: parseInt(normalized.slice(0, 2), 16),
    g: parseInt(normalized.slice(2, 4), 16),
    b: parseInt(normalized.slice(4, 6), 16),
  };
}

function sanitizeHexColorInput(value: string) {
  return value.replace(/[^0-9a-f]/gi, "").slice(0, 6).toUpperCase();
}

function normalizeHexColorInput(value: string) {
  const sanitized = sanitizeHexColorInput(value);
  if (sanitized.length !== 3 && sanitized.length !== 6) return "";
  return `#${sanitized}`;
}

function hexColorInputValue(value: string | undefined, fallback = "#000000") {
  return normalizeHexColorInput(value ?? "") || normalizeHexColorInput(fallback) || "#000000";
}

function cssColorToHex(value?: string) {
  const color = (value ?? "").trim();
  if (!color) return "";
  const normalizedHex = normalizeHexColorInput(color);
  if (normalizedHex) return normalizedHex;
  const rgbMatch = color.match(/^rgba?\((\d+),\s*(\d+),\s*(\d+)/i);
  if (!rgbMatch) return "";
  return `#${rgbMatch
    .slice(1, 4)
    .map((part) => Math.max(0, Math.min(255, Number(part))).toString(16).padStart(2, "0"))
    .join("")
    .toUpperCase()}`;
}

function colorWithAlpha(value: string | undefined, alpha: number, fallback: string) {
  const rgb = hexToRgb(value);
  if (!rgb) return fallback;
  return `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha})`;
}

function relativeLuminance(value?: string) {
  const rgb = hexToRgb(value);
  if (!rgb) return null;
  const channel = (color: number) => {
    const normalized = color / 255;
    return normalized <= 0.03928 ? normalized / 12.92 : ((normalized + 0.055) / 1.055) ** 2.4;
  };
  return 0.2126 * channel(rgb.r) + 0.7152 * channel(rgb.g) + 0.0722 * channel(rgb.b);
}

function contrastRatio(foreground?: string, background?: string) {
  const foregroundLuminance = relativeLuminance(foreground);
  const backgroundLuminance = relativeLuminance(background);
  if (foregroundLuminance === null || backgroundLuminance === null) return null;
  const light = Math.max(foregroundLuminance, backgroundLuminance);
  const dark = Math.min(foregroundLuminance, backgroundLuminance);
  return (light + 0.05) / (dark + 0.05);
}

function readableThemeText(text: string, background: string, fallbackDark = "#18212f", fallbackLight = "#ffffff") {
  const ratio = contrastRatio(text, background);
  if (ratio === null || ratio >= 4.5) return text;
  const darkRatio = contrastRatio(fallbackDark, background) ?? 0;
  const lightRatio = contrastRatio(fallbackLight, background) ?? 0;
  return darkRatio >= lightRatio ? fallbackDark : fallbackLight;
}

function statusColorVarName(status: string, token: "bg" | "text" | "border") {
  const slug = status.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "status";
  return `--app-status-${slug}-${token}`;
}

function statusBadgeStyle(status: string): CSSProperties {
  return {
    "--status-bg": `var(${statusColorVarName(status, "bg")}, var(--app-status-badge-bg))`,
    "--status-text": `var(${statusColorVarName(status, "text")}, var(--app-status-badge-text))`,
    "--status-border": `var(${statusColorVarName(status, "border")}, var(--app-status-badge-border))`,
  } as CSSProperties;
}

