const paymentMethodLabels: Record<string, string> = {
  ach: "ACH",
  "apple pay": "Apple Pay",
  card: "Credit Card",
  cash: "Cash",
  cas: "Cash",
  "cash app": "Cash App",
  cashapp: "Cash App",
  "cash check": "Cash",
  "cash/check": "Cash",
  cc: "Credit Card",
  check: "Check",
  cheque: "Check",
  "credit card": "Credit Card",
  "direct deposit": "Direct Deposit",
  offline: "Cash",
  other: "Other",
  paypal: "PayPal",
  "paypal instant": "PayPal",
  "paypal - instant": "PayPal",
  pnc: "PNC",
  venmo: "Venmo",
  "venmo cash": "Venmo",
  "venmo/cash": "Venmo",
  wise: "Wise",
  zelle: "Zelle",
  "zelle vemo": "Zelle",
  "zelle/vemo": "Zelle",
  "zelle venmo": "Zelle",
  "zelle/venmo": "Zelle",
};

function normalizePaymentMethodLabel(method: string) {
  const cleaned = method.trim().replace(/\s+/g, " ");
  if (!cleaned) return "";
  const key = cleaned.toLowerCase().replace(/[^\w/ -]+/g, "").replace(/\s+/g, " ");
  const looseKey = key.replace(/[-_]+/g, " ").replace(/\s+/g, " ").trim();
  if (paymentMethodLabels[key]) return paymentMethodLabels[key];
  if (paymentMethodLabels[looseKey]) return paymentMethodLabels[looseKey];
  if (looseKey.endsWith(" venmo")) return "Venmo";
  if (looseKey.includes("paypal")) return "PayPal";
  return cleaned
    .split(" ")
    .map((word) => {
      const lower = word.toLowerCase();
      if (["ach", "pnc"].includes(lower)) return lower.toUpperCase();
      if (lower === "paypal") return "PayPal";
      if (lower === "venmo") return "Venmo";
      return `${word.charAt(0).toUpperCase()}${word.slice(1).toLowerCase()}`;
    })
    .join(" ");
}

function mergePaymentMethods(values: string[]) {
  return Array.from(new Set(values.map(normalizePaymentMethodLabel).filter(Boolean))).sort((a, b) => a.localeCompare(b));
}

function bookingPatternUsesSequence(pattern: string) {
  return /\{\{seq\}\}/i.test(pattern);
}

function websiteBookingFieldValue(fields: WebsiteBookingSubmission["fields"], tokens: string[]) {
  const normalizedTokens = tokens.map(normalizeMatchValue);
  const match = fields.find((field) => {
    const label = normalizeMatchValue(field.label);
    return normalizedTokens.some((token) => label === token || label.includes(token));
  });
  return match?.value.trim() ?? "";
}

function websiteBookingClientName(fields: WebsiteBookingSubmission["fields"]) {
  const fullName = websiteBookingFieldValue(fields, ["name", "full name", "client name", "your name"]);
  const first = websiteBookingFieldValue(fields, ["first", "first name"]);
  const last = websiteBookingFieldValue(fields, ["last", "last name"]);
  if (first || last) return { first, last };
  const [firstPart = "", ...rest] = fullName.split(/\s+/).filter(Boolean);
  return { first: firstPart, last: rest.join(" ") };
}

