function couponClientKey(name: string, email?: string) {
  return normalizeMatchValue(email || name);
}

function couponRedemptionCount(coupon: Coupon) {
  return coupon.redemptions?.length ?? 0;
}

function couponRedemptionCountForPerson(coupon: Coupon, clientName: string, clientEmail?: string) {
  const key = couponClientKey(clientName, clientEmail);
  if (!key) return 0;
  return (coupon.redemptions ?? []).filter((redemption) => couponClientKey(redemption.clientName, redemption.clientEmail) === key).length;
}

function evaluateCoupon(coupon: Coupon, context: {
  subtotal: number;
  travelAmount?: number;
  services: string[];
  hours: number;
  date: string;
  clientName: string;
  clientEmail?: string;
  priorPurchaseCount: number;
}) {
  if (!coupon.active) return { valid: false, amount: 0, message: "This coupon is inactive." };
  if (coupon.startsAt && context.date < coupon.startsAt) return { valid: false, amount: 0, message: "This coupon is not active yet." };
  if (coupon.expiresAt && context.date > coupon.expiresAt) return { valid: false, amount: 0, message: "This coupon has expired." };
  if (coupon.maxRedemptions && couponRedemptionCount(coupon) >= coupon.maxRedemptions) return { valid: false, amount: 0, message: "This coupon has reached its usage limit." };
  if (coupon.maxRedemptionsPerPerson && couponRedemptionCountForPerson(coupon, context.clientName, context.clientEmail) >= coupon.maxRedemptionsPerPerson) {
    return { valid: false, amount: 0, message: "This coupon has already been used for this person." };
  }
  if (coupon.minimumSubtotal && context.subtotal < coupon.minimumSubtotal) return { valid: false, amount: 0, message: `Minimum subtotal is ${currency(coupon.minimumSubtotal, true)}.` };
  if (coupon.requiresPriorPurchase) {
    const requiredServices = coupon.requiredPurchaseServices ?? [];
    const hasRequiredService =
      !requiredServices.length ||
      context.services.some((service) => requiredServices.some((requiredService) => normalizeMatchValue(requiredService) === normalizeMatchValue(service)));
    if (!hasRequiredService) return { valid: false, amount: 0, message: "This coupon requires a qualifying service." };
    if (coupon.requiredPurchaseMinimumHours && context.hours < coupon.requiredPurchaseMinimumHours) {
      return { valid: false, amount: 0, message: `Requires at least ${coupon.requiredPurchaseMinimumHours} hours.` };
    }
    if (coupon.requiredPurchaseMinimumSubtotal && context.subtotal < coupon.requiredPurchaseMinimumSubtotal) {
      return { valid: false, amount: 0, message: `Requires at least ${currency(coupon.requiredPurchaseMinimumSubtotal, true)} purchased.` };
    }
  }
  if (coupon.appliesTo === "service" && coupon.serviceNames?.length) {
    const eligible = context.services.some((service) => coupon.serviceNames?.some((couponService) => normalizeMatchValue(couponService) === normalizeMatchValue(service)));
    if (!eligible) return { valid: false, amount: 0, message: "This coupon does not apply to the selected service." };
  }
  const discountBase = context.subtotal + (coupon.applyToTravel ? Math.max(0, context.travelAmount ?? 0) : 0);
  const rawAmount = coupon.discountType === "percentage" ? discountBase * (Math.max(0, coupon.amount) / 100) : Math.max(0, coupon.amount);
  const amount = Math.min(discountBase, Math.round(rawAmount * 100) / 100);
  if (amount <= 0) return { valid: false, amount: 0, message: "This coupon has no discount amount." };
  return { valid: true, amount, message: `${coupon.name || coupon.code} applied: -${currency(amount, true)}` };
}

function bestEligibleCoupon(coupons: Coupon[], context: Parameters<typeof evaluateCoupon>[1]) {
  return coupons.reduce<{ coupon: Coupon; amount: number; message: string } | null>((best, coupon) => {
    const result = evaluateCoupon(coupon, context);
    if (!result.valid) return best;
    if (!best || result.amount > best.amount) return { coupon, amount: result.amount, message: result.message };
    return best;
  }, null);
}

function openDatePickerFromEvent(event: SyntheticEvent<HTMLElement>) {
  const target = event.target;
  if (!(target instanceof HTMLInputElement) || !["date", "time"].includes(target.type)) return;
  try {
    target.showPicker?.();
  } catch {
    // Some browsers only allow the picker during a direct pointer interaction.
  }
}

