function formatExpenseCategory(category: string) {
  const cleaned = category.trim().replace(/\s+/g, " ");
  if (!cleaned) return "";
  const key = cleaned.toLowerCase();
  if (expenseCategoryLabels[key]) return expenseCategoryLabels[key];
  return cleaned
    .split(" ")
    .map((word) => {
      const lower = word.toLowerCase();
      if (["ach", "cc", "pnc"].includes(lower)) return lower.toUpperCase();
      if (lower === "paypal") return "PayPal";
      if (lower === "venmo") return "Venmo";
      return lower.charAt(0).toUpperCase() + lower.slice(1);
    })
    .join(" ");
}

function mergeExpenseCategories(values: string[]) {
  const byKey = new Map<string, string>();
  values.forEach((category) => {
    const formatted = formatExpenseCategory(category);
    if (!formatted) return;
    byKey.set(formatted.toLowerCase(), formatted);
  });
  return [...byKey.values()].sort((a, b) => a.localeCompare(b));
}

function mergeExpenses(current: Expense[], restored: Expense[]) {
  const seen = new Set<string>();
  const merged: Expense[] = [];
  for (const expense of [...current, ...restored]) {
    const signature = [
      expense.id,
      expense.date,
      expense.description.trim().toLowerCase(),
      expense.category.trim().toLowerCase(),
      expense.amount.toFixed(2),
      expense.jobId || "",
    ].join("|");
    if (seen.has(signature)) continue;
    seen.add(signature);
    merged.push(expense);
  }
  return merged.sort((a, b) => b.date.localeCompare(a.date));
}

function replaceExpenseOccurrence(current: Expense[], expenseId: string, occurrence: number, updatedExpense: Expense) {
  let seen = 0;
  return current.map((expense) => {
    if (expense.id !== expenseId) return expense;
    if (seen === occurrence) {
      seen += 1;
      return updatedExpense;
    }
    seen += 1;
    return expense;
  });
}

function removeExpenseOccurrence(current: Expense[], expenseId: string, occurrence: number) {
  let seen = 0;
  return current.filter((expense) => {
    if (expense.id !== expenseId) return true;
    if (seen === occurrence) {
      seen += 1;
      return false;
    }
    seen += 1;
    return true;
  });
}

function processingFeeDuplicateKey(expense: Expense) {
  return [
    expense.jobId || "",
    expense.date,
    (expense.reference || "").trim().toLowerCase(),
    roundedMoney(expense.amount).toFixed(2),
  ].join("|");
}

function isPayPalFeeExpense(expense: Expense) {
  return normalizeMatchValue(expense.category) === "paypal fees";
}

function isProcessingFeeExpense(expense: Expense) {
  const normalizedCategory = normalizeMatchValue(expense.category);
  return normalizedCategory === "processing fees" || normalizedCategory === "processing";
}

function removeDuplicateProcessingFeeExpenses(expenses: Expense[]) {
  const paypalFeeKeys = new Set(expenses.filter(isPayPalFeeExpense).map(processingFeeDuplicateKey));
  if (!paypalFeeKeys.size) return expenses;
  let changed = false;
  const next = expenses.filter((expense) => {
    const duplicate = isProcessingFeeExpense(expense) && paypalFeeKeys.has(processingFeeDuplicateKey(expense));
    if (duplicate) changed = true;
    return !duplicate;
  });
  return changed ? next : expenses;
}

function importedLossDateForJob(job: Pick<Job, "orderNumber">) {
  const orderKey = numericOrderKey(job.orderNumber);
  if (!orderKey) return "";
  const matchingDates = importedExpenses
    .filter((expense) => {
      const category = normalizeMatchValue(expense.category);
      if (category !== "cancelled" && category !== "loss") return false;
      const orderNumbers = extractExpenseOrderNumbers(`${expense.description} ${expense.reference ?? ""}`);
      return orderNumbers.some((orderNumber) => numericOrderKey(orderNumber) === orderKey);
    })
    .map((expense) => expense.date)
    .filter(validDateKey)
    .sort();
  return matchingDates[0] ?? "";
}

function originalPaymentDateForJob(job: Pick<Job, "orderNumber" | "date" | "payments">) {
  const paymentDates = [
    ...(job.payments ?? []).map((payment) => payment.date),
    ...(importedJobActivity.find((activity) => numericOrderKey(activity.orderNumber) === numericOrderKey(job.orderNumber))
      ?.payments.map((payment) => payment.date) ?? []),
  ]
    .filter(validDateKey)
    .sort();
  return paymentDates[0] ?? (validDateKey(job.date) ? job.date : dateKey(new Date()));
}

function lossDateForJob(job: Pick<Job, "orderNumber" | "date" | "payments">) {
  return importedLossDateForJob(job) || originalPaymentDateForJob(job);
}

function orderKeyForJob(job: Pick<Job, "orderNumber">) {
  const text = String(job.orderNumber || "").trim();
  const digits = text.replace(/\D/g, "");
  return digits || text.toLowerCase();
}

function displayDate(date: string) {
  const [year, month, day] = date.split("-");
  if (!year || !month || !day) return date;
  return `${month}/${day}/${year}`;
}

function displayMonth(monthKey: string) {
  const [year, month] = monthKey.split("-");
  const date = new Date(Number(year), Number(month) - 1, 1);
  if (!year || !month || !Number.isFinite(date.getTime())) return monthKey;
  return date.toLocaleDateString(undefined, { month: "short", year: "numeric" });
}

function displayDateTime(value: string) {
  const date = new Date(value);
  if (!Number.isFinite(date.getTime())) return value;
  return date.toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    year: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function customerVisibleOrderNotes(notes: string | undefined) {
  if (!notes) return "";
  const lines = notes.split("\n").map((line) => line.trim()).filter(Boolean);
  const isWebsiteRecap = lines.some((line) => line === "Website booking request" || line.startsWith("Form: Booking Request"));
  if (!isWebsiteRecap) return notes.trim();
  return lines
    .map((line) => {
      const match = /^(notes?|comments?|message|special requests?):\s*(.+)$/i.exec(line);
      return match?.[2]?.trim() ?? "";
    })
    .filter(Boolean)
    .join("\n");
}

function countLabel(count: number, singular: string, plural = `${singular}s`) {
  return `${count} ${count === 1 ? singular : plural}`;
}

function teamMemberStatus(member: TeamMember): TeamMemberStatus {
  if (member.status) return member.status;
  return member.active === false ? "inactive" : "active";
}

function teamMemberStatusLabel(status: TeamMemberStatus) {
  return teamMemberStatuses.find((item) => item.value === status)?.label || "Active";
}

function isActiveTeamMember(member: TeamMember) {
  return teamMemberStatus(member) === "active";
}

function isInactiveAlertStatus(status: string) {
  const normalized = normalizeMatchValue(status);
  return normalized === "archived" || normalized === "canceled" || normalized === "cancelled" || normalized === "postponed";
}

function isCrossedOutCalendarStatus(status: string) {
  const normalized = normalizeMatchValue(status);
  return normalized === "canceled" || normalized === "cancelled" || normalized === "postponed";
}

function serviceRequiresContract(product: string, contractServices?: string[]) {
  const selectedServices = contractServices ?? defaultSettings.contractServices ?? products;
  const normalizedProduct = normalizeMatchValue(product);
  return selectedServices.some((service) => normalizeMatchValue(service) === normalizedProduct);
}

function fillContractTemplate(
  template: ContractTemplate,
  client: { name: string; email: string; phone: string; jobs: Job[] },
  profile: Profile,
) {
  const jobCount = countLabel(client.jobs.length, "job");
  const nextJob = client.jobs[0];
  const replacements: Record<ContractShortcodeKey, string> = {
    businessName: profile.businessName || "Scarmack Productions",
    ownerName: profile.ownerName || "",
    clientName: client.name,
    clientEmail: client.email || "",
    clientPhone: client.phone || "",
    jobCount,
    jobDate: nextJob?.date || "",
    jobProduct: nextJob?.product || "",
    orderNumber: nextJob?.orderNumber || "",
  };
  return template.body.replace(/\{\{(\w+)\}\}/g, (_, key: string) =>
    key in replacements ? replacements[key as ContractShortcodeKey] : "",
  );
}

function legacyJobNote(job: Job): JobNote | null {
  const text = job.notes?.trim();
  if (!text) return null;
  return {
    id: `legacy-note-${job.id}`,
    text,
    createdAt: job.createdAt || `${job.date || dateKey(new Date())}T00:00:00`,
  };
}

function jobNotes(job: Job) {
  const notes = [...(job.notesLog ?? [])];
  if (!notes.length) {
    const legacy = legacyJobNote(job);
    if (legacy) notes.push(legacy);
  }
  return notes.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

function jobNotesForUpdate(job: Job) {
  if (job.notesLog?.length) return job.notesLog;
  const legacy = legacyJobNote(job);
  return legacy ? [legacy] : [];
}

function adminEntitySignature(value: unknown) {
  return JSON.stringify(value);
}

function adminFieldLabel(key: string) {
  return key
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/^./, (match) => match.toUpperCase());
}

function adminValueLabel(value: unknown) {
  if (value === undefined || value === null || value === "") return "blank";
  if (typeof value === "boolean") return value ? "Yes" : "No";
  if (typeof value === "number") return Number.isFinite(value) ? String(value) : "blank";
  if (typeof value === "string") return value;
  if (Array.isArray(value)) return `${value.length} item${value.length === 1 ? "" : "s"}`;
  return "updated";
}

function adminChangeSummary(before: Record<string, unknown>, after: Record<string, unknown>) {
  const ignored = new Set(["id"]);
  const keys = Array.from(new Set([...Object.keys(before), ...Object.keys(after)]))
    .filter((key) => !ignored.has(key))
    .filter((key) => adminEntitySignature(before[key]) !== adminEntitySignature(after[key]));
  const changes = keys.slice(0, 4).map((key) => {
    const beforeValue = adminValueLabel(before[key]);
    const afterValue = adminValueLabel(after[key]);
    if (beforeValue === "updated" || afterValue === "updated") return `${adminFieldLabel(key)} updated`;
    return `${adminFieldLabel(key)}: ${beforeValue} -> ${afterValue}`;
  });
  if (keys.length > changes.length) changes.push(`+${keys.length - changes.length} more`);
  return changes.join("; ");
}

function adminJobLabel(job: Job) {
  return `${clientNameForJob(job)}${job.orderNumber ? ` - Order #${job.orderNumber}` : ""}`;
}

function adminExpenseLabel(expense: Expense) {
  return `${formatExpenseCategory(expense.category) || "Expense"}${expense.amount ? ` - ${currency(expense.amount, true)}` : ""}`;
}

function adminClientLabel(client: ClientRecord) {
  return `${client.first} ${client.last}`.trim() || "Unnamed Client";
}

function adminMemberLabel(member: TeamMember) {
  return member.name || "Team Member";
}

function adminContractLabel(contract: ClientContract) {
  return contract.title || contract.status || "Contract";
}

function adminChecklistLabel(item: ChecklistItem) {
  return item.label || item.id;
}

function formatFileSize(bytes: number) {
  if (!Number.isFinite(bytes) || bytes <= 0) return "0 KB";
  const units = ["B", "KB", "MB", "GB"];
  let size = bytes;
  let unitIndex = 0;
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex += 1;
  }
  return `${size >= 10 || unitIndex === 0 ? Math.round(size) : size.toFixed(1)} ${units[unitIndex]}`;
}

