const makeHeroImageRecord = (imageDataUrl: string, website: WebsiteSettings, index = 0): WebsiteHeroImage => ({
  id: `hero-${Date.now()}-${index}-${Math.random().toString(36).slice(2, 8)}`,
  imageDataUrl,
  overlayEnabled: true,
  colorOverlayEnabled: true,
  overlayColor: defaultHeroOverlayColor,
  overlayOpacity: defaultHeroOverlayOpacity,
  eyebrow: website.heroEyebrow ?? website.tagline,
  headline: website.heroHeadline ?? website.pages[0]?.headline ?? "",
  body: website.heroBody ?? website.pages[0]?.body ?? "",
  buttonText: website.heroButtonText ?? "Book Now",
});

const defaultHeroOverlayColor = "#000000";
const defaultHeroOverlayOpacity = 38;

function heroOverlayStyle(hero?: Partial<WebsiteHeroImage> | null): CSSProperties {
  if (hero?.colorOverlayEnabled === false) return { backgroundColor: "transparent" };
  const overlayColor = hero?.overlayColor || defaultHeroOverlayColor;
  const overlayOpacity = clamp(hero?.overlayOpacity ?? defaultHeroOverlayOpacity, 0, 100) / 100;
  return {
    backgroundColor: colorWithAlpha(overlayColor, overlayOpacity, `rgba(0, 0, 0, ${overlayOpacity})`),
  };
}

function websiteHeroImagesForDisplay(website: WebsiteSettings): WebsiteHeroImage[] {
  if (website.heroImages?.length) return website.heroImages;
  const legacyImages = website.heroImageDataUrls?.length ? website.heroImageDataUrls : website.heroImageDataUrl ? [website.heroImageDataUrl] : [];
  return legacyImages.map((imageDataUrl, index) => ({
    ...makeHeroImageRecord(imageDataUrl, website, index),
    id: `legacy-hero-${index}`,
  }));
}

function heroDisplayText(globalValue: string | undefined, imageValue: string | undefined, fallback = "", defaultValue = "") {
  if (globalValue === "") return "";
  const globalText = globalValue ?? "";
  const globalIsDefault = globalText === "" || globalText === defaultValue || globalText === fallback;
  if (!globalIsDefault) return globalText;
  return imageValue ?? globalValue ?? fallback;
}

function adminThemeVars(website: WebsiteSettings, settings: Settings): CSSProperties {
  const accent = website.buttonColor || website.linkColor || defaultWebsiteSettings.buttonColor;
  const accentDark = website.linkColor || accent;
  const defaultText = website.textColor || defaultWebsiteSettings.textColor;
  const text = settings.adminTextColor || defaultText;
  const mutedText = settings.adminMutedTextColor || colorWithAlpha(text, 0.68, "#697381");
  const border = settings.adminBorderColor || colorWithAlpha(text, 0.16, "#d9e0e6");
  const panel = settings.adminPanelBackgroundColor || (website.contentTransparent ? "#ffffff" : website.contentBackgroundColor || "#ffffff");
  const background = settings.adminContentBackgroundColor || website.backgroundColor || defaultWebsiteSettings.backgroundColor;
  const menuBackground = settings.adminMenuBackgroundColor || panel;
  const menuText = settings.adminMenuTextColor || mutedText;
  const menuActiveBackground = settings.adminMenuActiveBackgroundColor || accent;
  const menuActiveText = settings.adminMenuActiveTextColor || website.buttonTextColor || "#ffffff";
  const searchPlaceholder = colorWithAlpha(text, 0.72, "#697381");
  const rowOdd = settings.adminRowOddColor || colorWithAlpha(accent, 0.08, "#f1f6fb");
  const rowEven = settings.adminRowEvenColor || colorWithAlpha(accent, 0.16, "#d8ecea");
  const rowHover = settings.adminRowHoverColor || "#fff8e8";
  const leftMenuBackground = settings.adminLeftMenuBackgroundColor || panel;
  const leftMenuText = settings.adminLeftMenuTextColor || mutedText;
  const leftMenuActiveBackground = settings.adminLeftMenuActiveBackgroundColor || rowOdd;
  const legacyCyanActiveText = settings.adminLeftMenuActiveTextColor?.toLowerCase() === "#24cfdb";
  const leftMenuActiveText = legacyCyanActiveText ? leftMenuText : settings.adminLeftMenuActiveTextColor || leftMenuText;
  const homeTileBackground = settings.adminHomeTileBackgroundColor || panel;
  const homeTileText = settings.adminHomeTileTextColor || text;
  const homeTileMutedText = settings.adminHomeTileMutedTextColor || mutedText;
  const homeTileBorder = settings.adminHomeTileBorderColor || border;
  const statusBadgeBackground = settings.adminStatusBadgeBackgroundColor || colorWithAlpha(accent, 0.16, "#edf1f4");
  const statusBadgeText = settings.adminStatusBadgeTextColor || accentDark;
  const statusBadgeBorder = settings.adminStatusBadgeBorderColor || colorWithAlpha(accent, 0.24, "#d9e0e6");
  const statusColors = Object.fromEntries(
    Object.entries({ ...defaultAdminStatusColors, ...(settings.adminStatusColors ?? {}) }).map(([status, colors]) => [
      status,
      statusColorsMatch(colors, defaultAdminStatusColors[status]) ? {} : colors,
    ]),
  );
  const amountPillBackground = settings.adminAmountPillBackgroundColor || rowOdd;
  const amountPillText = settings.adminAmountPillTextColor || text;
  const amountPillBorder = settings.adminAmountPillBorderColor || border;
  const chromeText = readableThemeText(text, panel);
  const chromeMutedText = colorWithAlpha(chromeText, 0.72, "#697381");

  return {
    "--ink": text,
    "--muted": mutedText,
    "--line": border,
    "--panel": panel,
    "--teal": accent,
    "--teal-dark": accentDark,
    "--coral": website.pageTitleColor || "#d85c4a",
    "--app-bg": background,
    "--app-panel": panel,
    "--app-topbar-bg": colorWithAlpha(website.headerBackgroundColor, 0.92, "rgba(255, 255, 255, 0.92)"),
    "--app-topbar-border": colorWithAlpha(text, 0.14, "rgba(217, 224, 230, 0.8)"),
    "--app-button": accent,
    "--app-button-text": website.buttonTextColor || "#ffffff",
    "--app-chrome-text": chromeText,
    "--app-chrome-muted": chromeMutedText,
    "--app-menu-bg": menuBackground,
    "--app-menu-text": menuText,
    "--app-menu-active-bg": menuActiveBackground,
    "--app-menu-active-text": menuActiveText,
    "--app-search-placeholder": searchPlaceholder,
    "--app-left-menu-bg": leftMenuBackground,
    "--app-left-menu-text": leftMenuText,
    "--app-left-menu-active-bg": leftMenuActiveBackground,
    "--app-left-menu-active-text": leftMenuActiveText,
    "--app-home-tile-bg": homeTileBackground,
    "--app-home-tile-text": homeTileText,
    "--app-home-tile-muted": homeTileMutedText,
    "--app-home-tile-border": homeTileBorder,
    "--app-status-badge-bg": statusBadgeBackground,
    "--app-status-badge-text": statusBadgeText,
    "--app-status-badge-border": statusBadgeBorder,
    "--app-amount-pill-bg": amountPillBackground,
    "--app-amount-pill-text": amountPillText,
    "--app-amount-pill-border": amountPillBorder,
    "--stripe-light": rowOdd,
    "--stripe-light-border": colorWithAlpha(accent, 0.2, "#c5d4e2"),
    "--stripe-strong": rowEven,
    "--stripe-strong-border": colorWithAlpha(accent, 0.3, "#a8cbc6"),
    "--stripe-hover": rowHover,
    ...Object.fromEntries(
      Object.entries(statusColors).flatMap(([status, colors]) => [
        [statusColorVarName(status, "bg"), colors.backgroundColor || statusBadgeBackground],
        [statusColorVarName(status, "text"), colors.textColor || statusBadgeText],
        [statusColorVarName(status, "border"), colors.borderColor || statusBadgeBorder],
      ]),
    ),
  } as CSSProperties;
}

const defaultPaymentMethods = mergePaymentMethods([
  "Cash",
  "Check",
  "Credit Card",
  "ACH",
  "PayPal",
  "Venmo",
  "Zelle",
  "Other",
  ...paymentLikeCategories,
]);

function normalizePaymentOptions(options?: PaymentOption[]) {
  const defaults = defaultSettings.paymentOptions ?? [];
  const byId = new Map(defaults.map((option) => [option.id, { ...option }]));
  (options ?? []).forEach((option) => {
    if (["paypal", "venmo", "cash-app", "apple-pay"].includes(option.id)) return;
    byId.set(option.id, {
      ...(byId.get(option.id) ?? {}),
      ...option,
      method: normalizePaymentMethodLabel(option.method || byId.get(option.id)?.method || option.label),
      label: option.label || byId.get(option.id)?.label || option.method || "Payment option",
      enabled: Boolean(option.enabled),
      payUrl: option.payUrl ?? "",
      handle: option.handle ?? "",
      instructions: option.instructions ?? "",
    });
  });
  return Array.from(byId.values());
}

function activePaymentOptions(settings: Settings) {
  return normalizePaymentOptions(settings.paymentOptions).filter((option) =>
    option.enabled && (option.payUrl?.trim() || option.handle?.trim() || option.instructions?.trim()),
  );
}

function paypalGatewayReady(settings: Settings) {
  const gateway = settings.paymentGateway;
  const credentials = paypalGatewayCredentials(settings);
  return Boolean(gateway?.paypalEnabled && credentials.clientId);
}

function paypalGatewayMode(settings: Settings) {
  return settings.paymentGateway?.paypalMode === "live" ? "live" : "sandbox";
}

function paypalGatewayCredentials(settings: Settings) {
  const gateway = settings.paymentGateway;
  const mode = paypalGatewayMode(settings);
  const clientId = mode === "live"
    ? gateway?.paypalLiveClientId?.trim() || gateway?.paypalClientId?.trim() || ""
    : gateway?.paypalSandboxClientId?.trim() || gateway?.paypalClientId?.trim() || "";
  const clientSecret = mode === "live"
    ? gateway?.paypalLiveClientSecret?.trim() || gateway?.paypalClientSecret?.trim() || ""
    : gateway?.paypalSandboxClientSecret?.trim() || gateway?.paypalClientSecret?.trim() || "";
  return { clientId, clientSecret };
}

function stripeGatewayReady(settings: Settings) {
  const gateway = settings.paymentGateway;
  return Boolean(gateway?.stripeEnabled && gateway.stripeSecretKey?.trim());
}

function inPersonCashEnabled(settings: Settings) {
  return Boolean(settings.paymentGateway?.inPersonCashEnabled);
}

