function normalizeEmail(value: string) {
  return value.trim().toLowerCase();
}

function accountIdForEmail(email: string) {
  return normalizeEmail(email).replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || `account-${crypto.randomUUID()}`;
}

function accountDataKey(account: AppAccount, key: string) {
  return `scarmack-books:account:${account.id}:${key.replace(/^scarmack-books:/, "")}`;
}

function readAccounts(): AppAccount[] {
  try {
    const parsed = JSON.parse(localStorage.getItem(accountStorageKey) || "[]") as AppAccount[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function writeAccounts(accounts: AppAccount[]) {
  localStorage.setItem(accountStorageKey, JSON.stringify(accounts));
}

function ensureAdminAccount() {
  const accounts = readAccounts();
  const email = normalizeEmail(adminEmail);
  if (accounts.some((account) => normalizeEmail(account.email) === email)) return accounts;
  const adminAccount: AppAccount = {
    id: accountIdForEmail(email),
    email,
    password: "",
    businessName: "Scarmack Productions",
    ownerName: "Sean Scarmack",
    plan: "yearly",
    paid: true,
    trialEndsAt: "",
    onboardingComplete: true,
    setupMode: "self",
    isAdmin: true,
  };
  const next = [adminAccount, ...accounts];
  writeAccounts(next);
  return next;
}

