function trialEndDate(days = 30) {
  const date = new Date();
  date.setDate(date.getDate() + days);
  return dateKey(date);
}

function trialStatusLabel(account: AppAccount) {
  if (account.isAdmin || account.paid || !account.trialEndsAt) return "";
  const today = dateKey(new Date());
  const daysLeft = Math.ceil((new Date(`${account.trialEndsAt}T00:00:00`).getTime() - new Date(`${today}T00:00:00`).getTime()) / 86400000);
  if (daysLeft < 0) return "Trial ended";
  if (daysLeft === 0) return "Trial ends today";
  return `${daysLeft} trial days left`;
}

function normalizeMatchValue(value?: string) {
  return value?.trim().toLowerCase() || "";
}

function canonicalTeamRole(role: string) {
  return normalizeMatchValue(role) === "editor" ? "Video Editor" : role;
}

function canonicalTeamRoleRates(roleRates: TeamRoleRate[] = []) {
  const byRole = new Map<string, TeamRoleRate>();
  roleRates
    .filter((rate) => rate.role.trim())
    .forEach((rate) => {
      const role = canonicalTeamRole(rate.role.trim());
      if (!byRole.has(normalizeMatchValue(role))) byRole.set(normalizeMatchValue(role), { ...rate, role });
    });
  return Array.from(byRole.values());
}

function defaultAdminRoleRates(existing: TeamRoleRate[] = []): TeamRoleRate[] {
  const byRole = new Map(
    canonicalTeamRoleRates(existing)
      .filter((rate) => normalizeMatchValue(rate.role) !== "admin")
      .map((rate) => [normalizeMatchValue(rate.role), rate] as const),
  );
  defaultTeamRoles.forEach((role) => {
    const key = normalizeMatchValue(role);
    if (!byRole.has(key)) byRole.set(key, { role, payType: "flat", rate: 0 });
  });
  return defaultTeamRoles
    .map((role) => byRole.get(normalizeMatchValue(role)))
    .filter((rate): rate is TeamRoleRate => Boolean(rate));
}

function adminTeamMemberFromProfile(profile: Profile): TeamMember {
  const name = profile.ownerName.trim() || profile.businessName.trim() || "Admin";
  return {
    id: "team-admin-profile",
    name,
    email: profile.email.trim(),
    phone: profile.phone.trim(),
    role: "Photographer",
    roleRates: defaultAdminRoleRates(),
    defaultPayType: "flat",
    defaultRate: 0,
    status: "active",
    active: true,
  };
}

function upsertAdminTeamMember(current: TeamMember[], profile: Profile) {
  const adminMember = adminTeamMemberFromProfile(profile);
  const hasAdminContact = Boolean(adminMember.email?.trim() || adminMember.phone?.trim());
  const adminEmail = normalizeMatchValue(adminMember.email);
  const adminName = normalizeMatchValue(adminMember.name);
  const existingIndex = current.findIndex((member) => {
    if (member.id === adminMember.id) return true;
    const memberEmail = normalizeMatchValue(member.email);
    if (adminEmail && memberEmail === adminEmail) return true;
    return adminName && normalizeMatchValue(member.name) === adminName;
  });
  const existing = existingIndex >= 0 ? current[existingIndex] : undefined;
  if (existing && !hasAdminContact) return current;
  const merged: TeamMember = {
    ...existing,
    ...adminMember,
    id: existing?.id || adminMember.id,
    email: adminMember.email || existing?.email || "",
    phone: adminMember.phone || existing?.phone || "",
    roleRates: defaultAdminRoleRates(existing?.roleRates),
  };
  const others = existingIndex >= 0 ? current.filter((_, index) => index !== existingIndex) : current;
  return [merged, ...others];
}

function findAdminTeamMember(current: TeamMember[], profile: Profile) {
  const adminMember = adminTeamMemberFromProfile(profile);
  const adminEmail = normalizeMatchValue(adminMember.email);
  const adminName = normalizeMatchValue(adminMember.name);
  return current.find((member) => {
    if (member.id === adminMember.id) return true;
    const memberEmail = normalizeMatchValue(member.email);
    if (adminEmail && memberEmail === adminEmail) return true;
    return adminName && normalizeMatchValue(member.name) === adminName;
  });
}

function isProfileAdminMember(memberId: string) {
  return memberId === "team-admin-profile";
}

function clampedLogoValue(value: number | undefined, range: { min: number; max: number; defaultValue: number }) {
  const next = Number(value);
  if (!Number.isFinite(next)) return range.defaultValue;
  return Math.min(range.max, Math.max(range.min, next));
}

function logoAspectRatio(profile: Pick<Profile, "logoAspectRatio">) {
  const ratio = Number(profile.logoAspectRatio);
  return Number.isFinite(ratio) && ratio > 0 ? Math.min(8, Math.max(0.25, ratio)) : defaultLogoAspectRatio;
}

function logoFitSize(profile: Pick<Profile, "logoWidth" | "logoMaxHeight" | "logoAspectRatio">) {
  const maxWidth = clampedLogoValue(profile.logoWidth, logoWidthRange);
  const maxHeight = clampedLogoValue(profile.logoMaxHeight, logoHeightRange);
  const aspectRatio = logoAspectRatio(profile);
  const widthFromHeight = maxHeight * aspectRatio;
  const width = Math.min(maxWidth, widthFromHeight);
  const height = width / aspectRatio;
  return { width: Math.round(width), height: Math.round(height) };
}

function logoLayoutStyle(profile: Pick<Profile, "logoWidth" | "logoMaxHeight" | "logoAspectRatio">): CSSProperties {
  const fit = logoFitSize(profile);
  return {
    "--logo-width": `${clampedLogoValue(profile.logoWidth, logoWidthRange)}px`,
    "--logo-max-height": `${clampedLogoValue(profile.logoMaxHeight, logoHeightRange)}px`,
    "--logo-fit-width": `${fit.width}px`,
    "--logo-fit-height": `${fit.height}px`,
  } as CSSProperties;
}

function expandLegacyLogoDefaults(profile: Profile) {
  const next: Profile = { ...profile };
  let changed = false;
  const width = Number(profile.logoWidth);
  const height = Number(profile.logoMaxHeight);
  const hasPreviousDefault = previousLogoDefaults.some(
    (item) => Math.round(width) === item.width && Math.round(height) === item.height,
  );
  if (!Number.isFinite(width) || hasPreviousDefault) {
    next.logoWidth = logoWidthRange.defaultValue;
    changed = true;
  }
  if (!Number.isFinite(height) || hasPreviousDefault) {
    next.logoMaxHeight = logoHeightRange.defaultValue;
    changed = true;
  }
  if (!Number.isFinite(Number(profile.logoAspectRatio))) {
    next.logoAspectRatio = defaultLogoAspectRatio;
    changed = true;
  }
  return changed ? next : profile;
}

function useStoredState<T>(key: string, initialValue: T, legacyKey?: string, resolveStoredValue?: (stored: T | undefined, legacy: T | undefined) => T | undefined) {
  const [value, setValue] = useState<T>(() => {
    const mirrorKey = `${key}:last-good`;
    try {
      const stored = localStorage.getItem(key);
      const parsedStored = stored ? (JSON.parse(stored) as T) : undefined;
      const legacy = legacyKey ? localStorage.getItem(legacyKey) : null;
      const parsedLegacy = legacy ? (JSON.parse(legacy) as T) : undefined;
      const mirror = localStorage.getItem(mirrorKey);
      const parsedMirror = mirror ? (JSON.parse(mirror) as T) : undefined;
      const resolved = resolveStoredValue
        ? [parsedStored, parsedLegacy, parsedMirror].reduce<T | undefined>((best, candidate) => resolveStoredValue(best, candidate), undefined)
        : parsedStored ?? parsedLegacy ?? parsedMirror;
      if (resolved !== undefined) {
        localStorage.setItem(key, JSON.stringify(resolved));
        localStorage.setItem(mirrorKey, JSON.stringify(resolved));
        return resolved;
      }
      if (legacy) {
        localStorage.setItem(key, legacy);
        localStorage.setItem(mirrorKey, legacy);
        return parsedLegacy as T;
      }
      return initialValue;
    } catch {
      return initialValue;
    }
  });

  const setStoredValue = useCallback((next: T | ((current: T) => T)) => {
    setValue((current) => {
      const resolved = typeof next === "function" ? (next as (current: T) => T)(current) : next;
      if (isProtectedStorageRegression(key, current, resolved)) {
        console.warn(`Blocked destructive storage regression for ${key}.`);
        return current;
      }
      try {
        const serialized = JSON.stringify(resolved);
        localStorage.setItem(key, serialized);
        localStorage.setItem(`${key}:last-good`, serialized);
      } catch (error) {
        console.warn(`Unable to save ${key} to local storage.`, error);
      }
      return resolved;
    });
  }, [key]);

  return [value, setStoredValue] as const;
}

function jobStoreScore(jobs?: Job[]) {
  if (!Array.isArray(jobs)) return -1;
  return (
    jobs.length * 1000 +
    jobs.reduce((sum, job) => sum + (job.payments?.length ?? 0) * 8 + (job.teamAssignments?.length ?? 0) * 4 + (job.workflow ? 2 : 0) + (job.orderNumber ? 1 : 0), 0)
  );
}

function chooseBestJobStore(stored?: Job[], legacy?: Job[]) {
  if (!stored && !legacy) return undefined;
  return jobStoreScore(legacy) > jobStoreScore(stored) ? legacy : stored;
}

function arrayStoreScore(value?: unknown[]) {
  return Array.isArray(value) ? value.length : -1;
}

function chooseBestArrayStore<T>(stored?: T[], legacy?: T[]) {
  if (!stored && !legacy) return undefined;
  return arrayStoreScore(legacy) > arrayStoreScore(stored) ? legacy : stored;
}

function profileStoreScore(profile?: Partial<Profile>) {
  if (!profile) return -1;
  return (
    (profile.logoDataUrl ? 1000 : 0) +
    (profile.businessName?.trim() ? 100 : 0) +
    (profile.ownerName?.trim() ? 40 : 0) +
    (profile.email?.trim() ? 20 : 0) +
    (profile.phone?.trim() ? 20 : 0) +
    (profile.taxId?.trim() ? 10 : 0)
  );
}

function chooseBestProfileStore(stored?: Profile, legacy?: Profile) {
  if (!stored && !legacy) return undefined;
  return profileStoreScore(legacy) > profileStoreScore(stored) ? legacy : stored;
}

function storageProtectionScore(key: string, value: unknown) {
  const normalizedKey = key.replace(/:last-good$/, "");
  if (normalizedKey.endsWith(":jobs:v2") || normalizedKey === "scarmack-books:jobs:v2") return jobStoreScore(value as Job[] | undefined);
  if (normalizedKey.endsWith(":profile") || normalizedKey === "scarmack-books:profile") return profileStoreScore(value as Partial<Profile> | undefined);
  if (normalizedKey.endsWith(":website-settings") || normalizedKey === "scarmack-books:website-settings") return websiteRestoreScore(value as Partial<WebsiteSettings> | undefined);
  if (
    normalizedKey.endsWith(":team-members") ||
    normalizedKey.endsWith(":clients") ||
    normalizedKey.endsWith(":expenses") ||
    normalizedKey.endsWith(":website-form-submissions") ||
    normalizedKey.endsWith(":website-abandoned-carts") ||
    normalizedKey.endsWith(":client-contracts") ||
    normalizedKey === "scarmack-books:team-members" ||
    normalizedKey === "scarmack-books:clients" ||
    normalizedKey === "scarmack-books:expenses"
  ) {
    return Array.isArray(value) ? value.length : -1;
  }
  return -1;
}

function isProtectedStorageRegression(key: string, current: unknown, next: unknown) {
  const currentScore = storageProtectionScore(key, current);
  const nextScore = storageProtectionScore(key, next);
  if (currentScore < 5) return false;
  if (nextScore < 0) return false;
  return nextScore < currentScore * 0.5;
}

function chooseBestSettingsStore(stored?: Settings, legacy?: Settings) {
  if (!stored && !legacy) return undefined;
  return settingsRestoreScore(legacy) > settingsRestoreScore(stored) ? legacy : stored;
}

function chooseBestWebsiteStore(stored?: WebsiteSettings, legacy?: WebsiteSettings) {
  if (!stored && !legacy) return undefined;
  const best = websiteRestoreScore(legacy) > websiteRestoreScore(stored) ? legacy : stored;
  return normalizeBackupWebsiteSettings(best);
}

