  function openTab(id: TabId, options?: { preserveExpandedJob?: boolean }) {
    if (id === "jobs" && !options?.preserveExpandedJob) {
      setExpandedJobId(null);
      setFocusedJobId(null);
    }
    if (id !== "clients") {
      setFocusedClientKey(null);
    }
    if (id === "dashboard") {
      setDashboardDetailRequest(null);
    }
    if (id === "website") {
      setWebsiteBuilderLocation((current) => ({
        ...current,
        section: "pages",
        pageId: "",
        sectionId: "",
        scrollY: 0,
      }));
      setWebsiteBuilderResetKey((current) => current + 1);
    }
    updateBrowserRoute(routeForAdminTab(id));
    setActiveTab(id);
    setShowHomepage(false);
    setIsJobsMenuOpen(false);
    setIsClientsMenuOpen(false);
    setIsReportsMenuOpen(false);
    setIsWebsiteMenuOpen(false);
    setIsSettingsMenuOpen(false);
  }

