                {website.galleryHidePhotoFilename !== true && (
                  <strong>{website.galleryRemoveFilenameExtension ? title.replace(/\.[^.]+$/, "") : title}</strong>
                )}
                {website.galleryHidePhotoIcons !== true && <small>{index === 0 ? "Downloads available" : "Favorites enabled"}</small>}
                <em>{index === 0 ? website.galleryDesktopOpenText ?? "Click to open" : website.galleryMobileOpenText ?? "Tap to open"}</em>
