                        <label className="page-access-toggle"><input type="checkbox" checked={Boolean(selectedWebsitePage.sidebarEnabled)} onChange={(event) => updatePage(selectedWebsitePage.id, { sidebarEnabled: event.target.checked })} /><span><strong>Side Bar</strong><small>Show side bar</small></span></label>
