                            <textarea onFocus={() => setActiveTextFieldKey("hero-headline")} onClick={() => setActiveTextFieldKey("hero-headline")} style={websiteTextStyle(website.heroHeadlineStyle)} value={heroHeadlineValue} onChange={(event) => updateWebsite({ heroHeadline: event.target.value })} aria-label="Hero headline" />
