                            <input onFocus={() => setActiveTextFieldKey("hero-body")} onClick={() => setActiveTextFieldKey("hero-body")} style={websiteTextStyle(website.heroBodyStyle)} value={heroBodyValue} onChange={(event) => updateWebsite({ heroBody: event.target.value })} aria-label="Hero supporting text" />
