                              {showFormatter(`block:${block.id}:title`) && <WebsiteTextFormatter value={block.titleStyle} defaultColor={pageTitleEditorColor} onChange={(titleStyle) => updatePageBlock(selectedWebsitePage.id, block.id, { titleStyle })} />}
