  oncePerDay: false,
  dateRangeEnabled: false,
  startDate: "",
  endDate: "",
  specialEvent: false,
  leadTimeDays: 0,
  maxAdvanceDays: 0,
  appointmentsPerTime: 1,
  customAvailability: false,
  availableDays: [0, 1, 2, 3, 4, 5, 6],
  availabilityMode: "all",
  availabilityWindows: {},
