  function cloneEmailRule(rule: EmailRule): EmailRule {
    return { ...rule, serviceNames: [...(rule.serviceNames ?? [])] };
  }

  function addEmailRule() {
    const firstTemplate = emailTemplates.find((template) => template.category.toLowerCase() === "booking") ?? emailTemplates[0];
    const id = `email-rule-${crypto.randomUUID()}`;
    const newRule: EmailRule = {
      id,
      name: `New Email Rule ${emailRules.length + 1}`,
      active: true,
      saved: false,
      templateId: firstTemplate?.id ?? "",
      trigger: "before-event",
      offsetAmount: 1,
      offsetUnit: "months",
      timeOfDay: "09:00",
      serviceScope: "all",
      serviceNames: [],
      balanceOnly: false,
      minimumBalance: 0,
      sendOnce: true,
      repeatUntilComplete: false,
      incompleteTask: "contract-unsigned",
      reminderEveryAmount: 3,
      reminderEveryUnit: "days",
      maxReminders: 0,
    };
    updateEmailRules([newRule, ...emailRules]);
    setEditingEmailRuleId(id);
    setEmailRuleEditSnapshot(null);
    setProfileMessage("Draft email rule created");
  }

  function emailRuleTriggerLabel(rule: EmailRule) {
    if (rule.trigger === "immediate") return "Send immediately";
    if (rule.trigger === "account-created") return "When account is created";
    if (rule.trigger === "booking-submitted") return "When booking is submitted";
    if (rule.trigger === "payment-received") return "When payment is received";
    if (rule.trigger === "before-event") return `${rule.offsetAmount} ${rule.offsetUnit} before event`;
    if (rule.trigger === "after-event") return `${rule.offsetAmount} ${rule.offsetUnit} after event`;
    if (rule.trigger === "after-booking") return `${rule.offsetAmount} ${rule.offsetUnit} after booking`;
    if (rule.trigger === "monthly-payment-due") return `Monthly on day ${rule.monthlyDay ?? 1}`;
    if (rule.trigger === "alert-center-recap") return `Every ${Math.max(1, Math.floor(rule.offsetAmount || 1))} ${rule.offsetUnit}`;
    return `${rule.offsetAmount} ${rule.offsetUnit} after payment is overdue`;
  }

  function emailRuleReminderLabel(rule: EmailRule) {
    if (isAlertCenterSummaryRule(rule)) return "Internal upcoming week alerts";
    if (!rule.repeatUntilComplete) return rule.balanceOnly ? `Balance due${rule.minimumBalance ? ` over ${currency(rule.minimumBalance, true)}` : ""}` : "Any balance";
    const taskLabel = rule.incompleteTask === "balance-due" ? "balance is paid" : rule.incompleteTask === "questionnaire-incomplete" ? "questionnaire is submitted" : "contract is signed";
    const amount = Math.max(1, Math.floor(rule.reminderEveryAmount ?? 3));
    const unit = rule.reminderEveryUnit ?? "days";
    const limit = rule.maxReminders && rule.maxReminders > 0 ? `, up to ${rule.maxReminders} reminders` : "";
    return `Remind every ${amount} ${unit} until ${taskLabel}${limit}`;
  }

  function emailRuleHasUnsavedChanges(rule: EmailRule) {
    if (rule.saved === false) return true;
    return Boolean(emailRuleEditSnapshot?.id === rule.id && JSON.stringify(cloneEmailRule(rule)) !== JSON.stringify(cloneEmailRule(emailRuleEditSnapshot)));
  }

