  async function clearEmailLog() {
    if (!window.confirm("Clear the email log? This removes the saved log from this mail server.")) return;
    setLoadingEmailLog(true);
    setEmailLogMessage("");
    try {
      await clearEmailLogOnServer();
      setEmailLog([]);
      setPreviewEmailLogEntry(null);
      setEmailLogMessage("Email log cleared.");
    } catch (error) {
      setEmailLogMessage(error instanceof Error ? error.message : "Email log could not be cleared.");
    } finally {
      setLoadingEmailLog(false);
    }
  }

  function exportEmailLog() {
    const csvEscape = (value: string | undefined) => `"${String(value || "").replace(/"/g, '""')}"`;
    const rows = [
      ["Sent At", "From", "To", "Cc", "Bcc", "Reply To", "Subject", "Text", "Message ID"],
      ...emailLog.map((entry) => [
        entry.sentAt,
        entry.from,
        entry.to,
        entry.cc || "",
        entry.bcc || "",
        entry.replyTo || "",
        entry.subject,
        entry.text || "",
        entry.messageId || "",
      ]),
    ];
    const csv = rows.map((row) => row.map(csvEscape).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `email-log-${dateKey(new Date())}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  }

  useEffect(() => {
    if (settingsSection === "email" && emailSettingsTab === "log") void refreshEmailLog();
  }, [settingsSection, emailSettingsTab]);

  function uploadProfileLogo(file?: File) {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const logoDataUrl = String(reader.result || "");
      const image = new Image();
      image.onload = () => {
        updateProfile({
          logoDataUrl,
          logoAspectRatio: image.naturalWidth && image.naturalHeight ? image.naturalWidth / image.naturalHeight : defaultLogoAspectRatio,
          showLogo: true,
        });
      };
      image.onerror = () => updateProfile({ logoDataUrl, showLogo: true });
      image.src = logoDataUrl;
    };
    reader.readAsDataURL(file);
  }

  function recordDraftLogoSize(event: SyntheticEvent<HTMLImageElement>) {
    const { naturalWidth, naturalHeight } = event.currentTarget;
    if (!naturalWidth || !naturalHeight) return;
    const nextRatio = naturalWidth / naturalHeight;
    if (Math.abs(logoAspectRatio(profileDraft) - nextRatio) < 0.01) return;
    updateProfile({ logoAspectRatio: nextRatio });
  }

