    onSettingsChange({
      venues: [
        ...managedVenues,
        {
          id: `venue-${crypto.randomUUID()}`,
          name,
          address: venueAddressDraft.trim(),
          city: venueCityDraft.trim(),
          state: normalizeStateAbbreviation(venueStateDraft),
          zip: venueZipDraft.trim(),
        },
      ],
    });
    setVenueNameDraft("");
    setVenueAddressDraft("");
    setVenueCityDraft("");
    setVenueStateDraft("PA");
    setVenueZipDraft("");
    setAddingVenue(false);
