  async function lookupDraftVenue() {
    const name = venueNameDraft.trim();
    if (!name) return;
    setLocationLookupId("__new__");
    setLocationLookupMessage("");
    setLocationLookupMessageId("__new__");
    try {
      const result = await lookupLocationAddress([name, venueCityDraft, venueStateDraft].filter(Boolean).join(", "), settings.googleMapsApiKey);
      setVenueAddressDraft(result.address);
      setVenueCityDraft(result.city);
      setVenueStateDraft(result.state);
      setVenueZipDraft(result.zip);
      setLocationLookupMessage(`Updated ${name}.`);
    } catch (error) {
      setLocationLookupMessage(error instanceof Error ? error.message : "Location lookup failed.");
    } finally {
      setLocationLookupId("");
    }
  }

  async function lookupSavedVenue(venueItem: VenueLocation) {
    const name = venueItem.name.trim();
    if (!name) return;
    setLocationLookupId(venueItem.id);
    setLocationLookupMessage("");
    setLocationLookupMessageId(venueItem.id);
    try {
      const result = await lookupLocationAddress([name, venueItem.city, venueItem.state].filter(Boolean).join(", "), settings.googleMapsApiKey);
      updateVenue(venueItem.id, result);
      setLocationLookupMessage(`Updated ${name}.`);
    } catch (error) {
      setLocationLookupMessage(error instanceof Error ? error.message : "Location lookup failed.");
    } finally {
      setLocationLookupId("");
    }
  }

