  function savePayment(event: FormEvent) {
    event.preventDefault();
    if (paymentDraft.amount <= 0 || !paymentDraft.method) return;
    const payment = {
      id: `payment-${crypto.randomUUID()}`,
      date: paymentDraft.date,
      method: paymentDraft.method.trim() || "Other",
      reference: paymentDraft.reference.trim(),
      amount: paymentDraft.amount,
    };
    onUpdate?.({
      ...job,
      payments: [payment, ...(job.payments ?? [])],
      overrides: undefined,
    });
    setPaymentDraft({
      date: new Date().toISOString().slice(0, 10),
      method: paymentMethods[0] || payment.method,
      reference: "",
      amount: 0,
    });
    setAddingPayment(false);
  }

  function savePaymentSchedule(event: FormEvent) {
    event.preventDefault();
    if (!onUpdate || scheduleBalance <= 0 || !scheduleDraft.method) return;
    const count =
      scheduleDraft.mode === "count"
        ? Math.max(1, Math.floor(scheduleDraft.payments || 1))
        : Math.max(1, Math.ceil(scheduleBalance / Math.max(0.01, scheduleDraft.amount || 0.01)));
    const scheduleId = `schedule-${crypto.randomUUID()}`;
    let remaining = Math.round(scheduleBalance * 100);
    const scheduledPayments = Array.from({ length: count }, (_, index) => {
      const amountInCents =
        scheduleDraft.mode === "count"
          ? index === count - 1
            ? remaining
            : Math.round((scheduleBalance * 100) / count)
          : index === count - 1
            ? remaining
            : Math.min(remaining, Math.round(Math.max(0.01, scheduleDraft.amount) * 100));
      remaining -= amountInCents;
      const referenceParts = [`Scheduled payment ${index + 1} of ${count}`];
      if (scheduleDraft.reference.trim()) referenceParts.push(scheduleDraft.reference.trim());
      return {
        id: `payment-${crypto.randomUUID()}`,
        date: scheduleDateForFrequency(scheduleDraft.startDate, index, scheduleDraft.frequency),
        method: scheduleDraft.method.trim() || "Scheduled",
        reference: referenceParts.join(" - "),
        amount: Math.max(0, amountInCents) / 100,
        status: "scheduled" as const,
        scheduleId,
      };
    }).filter((payment) => payment.amount > 0);
    if (!scheduledPayments.length) return;
    onUpdate({
      ...job,
      payments: [...scheduledPayments, ...(job.payments ?? [])],
      overrides: undefined,
    });
    setScheduleDraft((current) => ({ ...current, reference: "" }));
    setAddingPaymentSchedule(false);
  }

  function saveJobExpense(event: FormEvent) {
    event.preventDefault();
    if (!expenseDraft.category || expenseDraft.amount <= 0 || addingJobExpenseCategory) return;
    const category = formatExpenseCategory(expenseDraft.category);
    onAddExpense?.({
      id: `expense-${crypto.randomUUID()}`,
      date: expenseDraft.date,
      description: `${client} expense`,
      amount: expenseDraft.amount,
      category,
      reference: expenseDraft.reference.trim(),
      jobId: job.id,
    });
    onUpdate?.(appendJobActivityLog(job, jobActivityEntry("Expenses", "Expense added", `${category} ${currency(expenseDraft.amount)} on ${displayDate(expenseDraft.date)}`)));
    setExpenseDraft({
      date: new Date().toISOString().slice(0, 10),
      category: expenseCategories[0] || "",
      reference: "",
      amount: 0,
    });
    setAddingExpense(false);
  }

  function applyBalanceLoss() {
    if (!onAddExpense || !onUpdate || math.balance <= 0 || !canWriteOffBalance) return;
    const lossAmount = Math.round(math.balance * 100) / 100;
    onAddExpenseCategory?.("Loss");
    onAddExpense({
      id: `expense-${crypto.randomUUID()}`,
      date: lossDateForJob(job),
      description: `${client} balance write-off`,
      amount: lossAmount,
      category: "Loss",
      reference: job.orderNumber ? `Order #${job.orderNumber} balance write-off` : "Balance write-off",
      jobId: job.id,
    });
    onUpdate({
      ...appendJobActivityLog(job, jobActivityEntry("Expenses", "Balance written off", currency(lossAmount))),
      overrides: {
        ...job.overrides,
        balance: 0,
      },
    });
  }

  function applyDraftBalanceLoss() {
    const currentMath = calculateJob(draft, settings);
    const draftCanWriteOffBalance =
      (validDateKey(draft.date) && draft.date <= dateKey(new Date())) || isInactiveAlertStatus(draft.status);
    if (!onAddExpense || currentMath.balance <= 0 || !draftCanWriteOffBalance) return;
    setDraftBalanceLoss(Math.round(currentMath.balance * 100) / 100);
    setDraft((current) => ({
      ...current,
      overrides: {
        ...current.overrides,
        balance: 0,
      },
    }));
  }

