  function deletePayment(paymentId: string, trigger?: HTMLElement | null) {
    const pageScrollY = window.scrollY;
    const paymentTable = trigger?.closest(".payment-activity-table") as HTMLElement | null;
    const tableScrollTop = paymentTable?.scrollTop ?? null;
    onUpdate?.({
      ...job,
      payments: (job.payments ?? []).filter((payment) => payment.id !== paymentId),
      overrides: undefined,
    });
    if (tableScrollTop !== null) {
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          window.scrollTo({ top: pageScrollY });
          const nextPaymentTable = document.querySelector(".payment-activity-table") as HTMLElement | null;
          if (nextPaymentTable) nextPaymentTable.scrollTop = tableScrollTop;
        });
      });
    }
    setEditingPaymentId(null);
  }

  function expenseRowKey(expense: Expense, index: number) {
    return `${expense.id}-${index}`;
  }

  function startExpenseEdit(expense: Expense, index: number) {
    setEditingExpenseKey(expenseRowKey(expense, index));
    setExpenseEditDraft({
      date: expense.date,
      category: formatExpenseCategory(expense.category),
      reference: expense.reference || "",
      amount: expense.amount,
    });
  }

  function saveExpenseEdit(expense: Expense) {
    if (!expenseEditDraft.category || expenseEditDraft.amount <= 0) return;
    onUpdateExpense?.({
      ...expense,
      date: expenseEditDraft.date,
      category: formatExpenseCategory(expenseEditDraft.category),
      reference: expenseEditDraft.reference.trim(),
      amount: expenseEditDraft.amount,
    });
    onUpdate?.(appendJobActivityLog(job, jobActivityEntry("Expenses", "Expense adjusted", `${formatExpenseCategory(expenseEditDraft.category)} ${currency(expenseEditDraft.amount)}`)));
    setEditingExpenseKey(null);
  }

  function expenseOccurrenceIndex(expense: Expense) {
    const sourceIndex = expenseEntries.indexOf(expense);
    if (sourceIndex < 0) return 0;
    return expenseEntries.slice(0, sourceIndex + 1).filter((item) => item.id === expense.id).length - 1;
  }

  function saveTeamPaymentExpenseEdit(expense: Expense) {
    if (!expenseEditDraft.category || expenseEditDraft.amount <= 0) return;
    const hasDuplicateId = expenseEntries.filter((item) => item.id === expense.id).length > 1;
    const updatedExpense = {
      ...expense,
      id: hasDuplicateId ? `expense-${crypto.randomUUID()}` : expense.id,
      date: expenseEditDraft.date,
      category: formatExpenseCategory(expenseEditDraft.category),
      reference: expenseEditDraft.reference.trim(),
      amount: expenseEditDraft.amount,
    };
    if (onUpdateExpenseOccurrence) onUpdateExpenseOccurrence(expense.id, expenseOccurrenceIndex(expense), updatedExpense);
    else onUpdateExpense?.(updatedExpense);
    onUpdate?.(appendJobActivityLog(job, jobActivityEntry("Expenses", "Team pay expense adjusted", currency(updatedExpense.amount))));
    setEditingExpenseKey(null);
  }

