  function updateDraftSchedule(service: string, next: Partial<JobServiceSchedule>) {
    setDraft((current) => {
      const rows = jobServiceScheduleRows(current);
      const matchKey = normalizeMatchValue(service);
      const updatedRows = rows.map((row) => (normalizeMatchValue(row.service) === matchKey ? { ...row, ...next } : row));
      const primary = updatedRows[0];
      return {
        ...current,
        serviceSchedule: updatedRows,
        location: serviceScheduleAddress(primary) || current.location,
        startTime: primary?.startTime ?? current.startTime,
        endTime: primary?.endTime ?? current.endTime,
      };
    });
  }

