    updateDraftSchedule(service, {
      locationName: name,
      ...(savedLocation
        ? {
            location: savedLocation.address || "",
            locationCity: savedLocation.city || "",
            locationState: savedLocation.state ? normalizeStateAbbreviation(savedLocation.state) : "",
            locationZip: savedLocation.zip || "",
          }
        : {}),
    });
